sheet.mermaid-diagram:
flowchart TB A([User Question]) B[Input Validation] C[Scope & Security Check] D[Knowledge Base Retrieval] E[Context & Confidence Check] F[AI Response Generation] G[Response Validation] H([Return Response])
A --> B B --> C C --> D D --> E E --> F F --> G G --> H
classDef process fill:#1c5d8c,stroke:#0d2b45,stroke-width:2px,color:#ffffff; classDef startend fill:#0d2b45,stroke:#e8a33d,stroke-width:3px,color:#ffffff;
class A,H startend; class B,C,D,E,F,G process;

flowchart TB
    A([User Question])
    B[Search Knowledge Base]
    C{Relevant Context Available?}
    D[Generate Response]
    E{Is Query Related to Theta?}
    F([Suggest Contact or Official Page])
    G([Politely Decline])

    A --> B
    B --> C
    C --|Yes|--> D
    C --|No|--> E
    E --|Yes|--> F
    E --|No|--> G

    classDef process fill:#1c5d8c,stroke:#0d2b45,stroke-width:2px,color:#ffffff;
    classDef startend fill:#0d2b45,stroke:#e8a33d,stroke-width:3px,color:#ffffff;
    classDef decision fill:#fdf6ea,stroke:#e8a33d,stroke-width:2px,color:#b5791c;

    class A,D,F,G startend;
    class B process;
    class C,E decision;
